package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP03CambiarEstadoPreparacionTest extends BaseTest {    @Test    void cocineroCambiaPedidoAEnPreparacion() {        try {            System.out.println("Ejecutando HP-03: Cambiar pedido a En Preparación");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage = new CocineroPage(driver);            Assertions.assertTrue(                    cocineroPage.seccionPendientesVisible(),                    "No se muestra la sección Pedidos Pendientes."            );            cocineroPage.comenzarPreparacion();            Thread.sleep(3000);            Assertions.assertTrue(                    cocineroPage.seccionPreparacionVisible(),                    "No se muestra la sección Pedidos en Preparación."            );            Assertions.assertTrue(                    cocineroPage.botonMarcarComoEntregadoVisible(),                    "El pedido no cambió correctamente a En Preparación."            );            System.out.println("HP-03 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-03: " + e.getMessage());        }    }}